    <!-- ===== LAZY LOADING OPTIMIZATION (Advanced) ===== -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/lazysizes/5.3.2/lazysizes.min.js" async></script>
    <script>
        // ===== ADVANCED LAZY LOADING - XỬ LÝ IMG + BG + CSS VARIABLES =====
        document.addEventListener('DOMContentLoaded', function() {
            // ========== 1. NATIVE IMG TAGS ==========
            const images = document.querySelectorAll('img:not([loading])');
            images.forEach((img, index) => {
                // Bỏ qua 5 ảnh đầu tiên (hero/banner)
                if (index < 5) return;
                img.loading = 'lazy';
                img.classList.add('lazyload');
            });
            // ========== 2. INLINE BACKGROUND IMAGES ==========
            const bgElements = document.querySelectorAll('[style*="background-image"]');
            const bgObserver = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('lazyloaded');
                        bgObserver.unobserve(entry.target);
                    }
                });
            }, {
                rootMargin: '150px 0px',
                threshold: 0.01
            });
            bgElements.forEach(el => bgObserver.observe(el));

            // ========== 3. CSS VARIABLES (--banner-image, etc) ==========
            const cssVarElements = document.querySelectorAll('[style*="--"]');
            const cssVarObserver = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        const element = entry.target;
                        const style = element.getAttribute('style');

                        // Extract tất cả CSS variables từ style attribute
                        const cssVarRegex = /--([\w-]+):\s*url\(['"]?([^'")\]]+)['"]?\)/g;
                        let match;

                        while ((match = cssVarRegex.exec(style)) !== null) {
                            const varName = '--' + match[1];
                            const varValue = match[2];

                            // Áp dụng biến CSS vào element
                            element.style.setProperty(varName, `url('${varValue}')`);
                        }

                        element.classList.add('lazyloaded');
                        cssVarObserver.unobserve(element);
                        console.log('💾 CSS var loaded on:', element.className);
                    }
                });
            }, {
                rootMargin: '150px 0px',
                threshold: 0.01
            });
            cssVarElements.forEach(el => cssVarObserver.observe(el));

            // ========== 4. CLASS-BASED BACKGROUND IMAGES ==========
            // Nếu background-image được định nghĩa trong CSS class
            const classBasedElements = document.querySelectorAll(
                '[class*="banner"], [class*="hero"], [class*="bg-"]');
            const classBasedObserver = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('lazyloaded');
                        classBasedObserver.unobserve(entry.target);
                    }
                });
            }, {
                rootMargin: '150px 0px',
                threshold: 0.01
            });
            classBasedElements.forEach(el => {
                if (!el.classList.contains('lazyloaded')) {
                    classBasedObserver.observe(el);
                }
            });

            // ========== SUMMARY ==========
            const totalElements = images.length + bgElements.length + cssVarElements.length + classBasedElements
                .length;
        });
    </script>

